import SwiftUI

struct MainView: View {
    @Bindable var store: StoreOf<MainFeature>

    private let calendar = Calendar.current

    var body: some View {
        ZStack(alignment: .topTrailing) {
            Color(hex: "FAF8F5").ignoresSafeArea()

