private extension Date {
    static func fixed(_ year: Int, _ month: Int, _ day: Int) -> Date {
        Calendar.current.date(from: DateComponents(year: year, month: month, day: day))!
    }
}

/// 설치일부터 어제까지 80% 확률로 기록 날짜를 생성 (5번째 날마다 스킵)
private func mockRecordedDates(from installDate: Date, to lastDay: Date) -> [Date] {
    var dates: [Date] = []
    let cal = Calendar.current
    var current = cal.startOfDay(for: installDate)
    let end = cal.startOfDay(for: lastDay)
    var index = 0
    while current <= end {
        if index % 5 != 4 {  // ~80% 기록
            dates.append(current)
        }
        current = cal.date(byAdding: .day, value: 1, to: current)!
        index += 1
    }
    return dates
}

#Preview {
    let testToday = Date.fixed(2027, 3, 30)
    let testInstall = Date.fixed(2026, 4, 15)
    let yesterday = Calendar.current.date(byAdding: .day, value: -1, to: testToday)!
    let allDates = mockRecordedDates(from: testInstall, to: yesterday)

    MainView(
        store: Store(
            initialState: MainFeature.State(
                today: testToday,
                installDate: testInstall
            )
        ) {
            MainFeature()
        } withDependencies: {
            $0.date = .constant(testToday)
            $0.diaryClient.fetchDiaries = { [allDates] month in
                let cal = Calendar.current
                let y = cal.component(.year, from: month)
                let m = cal.component(.month, from: month)
                // Date만 있는 더미 Diary 반환
                return allDates
                    .filter {
                        cal.component(.year, from: $0) == y &&
                        cal.component(.month, from: $0) == m
                    }
                    .map { Diary(date: $0) }
            }
        }
    )
}

