        return VStack(alignment: .leading, spacing: 8) {
            Text(verbatim: String(year))
                .font(.gulim(13))
                .foregroundColor(Color(hex: "AAAAAA"))

            HStack(spacing: 8) {
                Button { store.send(.prevMonthTapped) } label: {
                    Image("icon_arrow_left")
                        .renderingMode(.template)
                        .foregroundColor(canGoPrev ? .black : Color(hex: "D0D0D0"))
                        .padding(.trailing, 12)
                        .padding(.vertical, 10)
                }
                .contentShape(Rectangle())
                .disabled(!canGoPrev)

                Text(verbatim: "\(month)월")
                    .font(.gulim(20))
                    .foregroundColor(.black)

                Button { store.send(.nextMonthTapped) } label: {
                    Image("icon_arrow_right")
                        .renderingMode(.template)
                        .foregroundColor(canGoNext ? .black : Color(hex: "D0D0D0"))
                        .padding(.leading, 12)
                        .padding(.vertical, 10)
                }
                .contentShape(Rectangle())
                .disabled(!canGoNext)
            }
        }
        .frame(maxWidth: .infinity, alignment: .leading)
    }

    // MARK: - Helpers

    private var currentTheme: MonthlyTheme? {
        let year = calendar.component(.year, from: store.currentMonth)
        let month = calendar.component(.month, from: store.currentMonth)
        return MonthlyTheme.all.first { $0.year == year && $0.month == month }
    }

    private var canGoPrev: Bool {
        let prev = calendar.date(byAdding: .month, value: -1, to: store.currentMonth)!
        return prev >= store.installDate.startOfMonth
    }

    private var canGoNext: Bool {
        let next = calendar.date(byAdding: .month, value: 1, to: store.currentMonth)!
        let maxMonth = calendar.date(byAdding: .month, value: 12, to: store.today)!.startOfMonth
        return next <= maxMonth
    }
}

