import ComposableArchitecture
import SwiftData
import SwiftUI

@main
struct DottonApp: App {
    let store: StoreOf<MainFeature> = {
        #if DEBUG
        let testToday = Calendar.current.date(from: DateComponents(year: 2027, month: 3, day: 30))!
        let testInstall = Calendar.current.date(from: DateComponents(year: 2026, month: 4, day: 15))!
        let yesterday = Calendar.current.date(byAdding: .day, value: -1, to: testToday)!
        let allDates = mockRecordedDates(from: testInstall, to: yesterday)
        return Store(initialState: MainFeature.State(today: testToday, installDate: testInstall)) {
            MainFeature()
        } withDependencies: {
            $0.date = .constant(testToday)
            $0.diaryClient.fetchDiaries = { month in
                let cal = Calendar.current
                let y = cal.component(.year, from: month)
                let m = cal.component(.month, from: month)
                return allDates
                    .filter {
                        cal.component(.year, from: $0) == y &&
                        cal.component(.month, from: $0) == m
                    }
                    .map { Diary(date: $0) }
            }
        }
        #else
        let installDate: Date = {
            if let saved = UserDefaults.standard.object(forKey: "installDate") as? Date {
                return saved
            }
            let now = Date()
            UserDefaults.standard.set(now, forKey: "installDate")
            return now
        }()
        return Store(initialState: MainFeature.State(today: Date(), installDate: installDate)) {
            MainFeature()
        }
        #endif
    }()

    var body: some Scene {
        WindowGroup {
            MainView(store: store)
        }
        .modelContainer(for: Diary.self)
    }
}

private func mockRecordedDates(from installDate: Date, to lastDay: Date) -> [Date] {
    var dates: [Date] = []
    let cal = Calendar.current
    var current = cal.startOfDay(for: installDate)
    let end = cal.startOfDay(for: lastDay)
    var index = 0
    while current <= end {
        if index % 20 < 17 {
            dates.append(current)
        }
        current = cal.date(byAdding: .day, value: 1, to: current)!
        index += 1
    }
    return dates
}

