        return Store(initialState: MainFeature.State(today: testToday, installDate: testInstall)) {
            MainFeature()
        } withDependencies: {
            $0.date = .constant(testToday)
            $0.diaryClient.fetchDiaries = { month in
                let cal = Calendar.current
                let y = cal.component(.year, from: month)
                let m = cal.component(.month, from: month)
                return allDates.filter {
                    cal.component(.year, from: $0) == y &&
                    cal.component(.month, from: $0) == m
                }
            }
        }
        #else
        let installDate: Date = {
            if let saved = UserDefaults.standard.object(forKey: "installDate") as? Date {
                return saved
            }
            let now = Date()
            UserDefaults.standard.set(now, forKey: "installDate")
            return now
        }()
        return Store(initialState: MainFeature.State(today: Date(), installDate: installDate)) {
            MainFeature()
        }
        #endif
    }()

    var body: some Scene {
        WindowGroup {
            MainView(store: store)
        }
        .modelContainer(for: Diary.self)
    }
